module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [7:0] dividend_abs;
    reg [7:0] divisor_abs;
    reg [7:0] remainder;
    reg [7:0] quotient;
    reg [3:0] count;
    reg [15:0] shift_reg;
    reg [15:0] neg_divisor;
    reg [3:0] shift_count;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_abs <= 8'b0;
            divisor_abs <= 8'b0;
            remainder <= 8'b0;
            quotient <= 8'b0;
            count <= 4'b0;
            shift_reg <= 16'b0;
            neg_divisor <= 16'b0;
            shift_count <= 4'b0;
            res_valid <= 1'b0;
            result <= 16'b0;
        end
        else begin
            if (opn_valid) begin
                if (sign) begin
                    dividend_abs <= (dividend[7]) ? ~dividend + 1 : dividend;
                    divisor_abs <= (divisor[7]) ? ~divisor + 1 : divisor;
                    remainder <= dividend_abs;
                    quotient <= 8'b0;
                    count <= 4'b0;
                    shift_reg <= {8'b0, dividend_abs, 1'b0};
                    neg_divisor <= {1'b0, ~divisor_abs + 1'b1, 7'b0};
                    shift_count <= 4'b0;
                end
                else begin
                    dividend_abs <= dividend;
                    divisor_abs <= divisor;
                    remainder <= dividend_abs;
                    quotient <= 8'b0;
                    count <= 4'b0;
                    shift_reg <= {8'b0, dividend_abs, 1'b0};
                    neg_divisor <= {1'b0, divisor_abs, 7'b0};
                    shift_count <= 4'b0;
                end
            end
            else if (shift_count == 4'b1000) begin
                if (sign && (dividend[7] ^ divisor[7])) begin
                    shift_reg <= {shift_reg[14:0], 1'b1};
                    remainder <= remainder - divisor_abs;
                end
                else begin
                    shift_reg <= {shift_reg[14:0], 1'b0};
                    remainder <= remainder;
                end
                shift_count <= 4'b0;
            end
            else begin
                shift_reg <= {shift_reg[15:1], 1'b0};
                remainder <= remainder;
                shift_count <= shift_count + 1;
            end

            if (shift_count == 4'b1000) begin
                quotient <= {quotient[6:0], 1'b1};
                shift_count <= 4'b0;
            end
            else if (remainder == 8'b0) begin
                quotient <= {quotient[6:0], 1'b0};
                shift_count <= 4'b0;
            end
            else begin
                quotient <= quotient;
            end

            if (count == 4'b1000) begin
                res_valid <= 1'b1;
                result <= {sign && (dividend[7] ^ divisor[7]), quotient, remainder};
            end
            else begin
                res_valid <= 1'b0;
                result <= result;
            end
        end
    end

endmodule
